import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { Activity, Archive, LayoutDashboard, LogOut, Terminal } from 'lucide-react';

const Navbar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    <nav style={navWrapper}>
      {/* ── Brand Section (Left) ── */}
      <Link to="/" style={brandLink}>
        <Terminal size={20} color="var(--accent-primary)" />
        <span style={brandText}>FINIFY_AI</span>
      </Link>

      {/* ── Navigation Links (Center) ── */}
      <div style={navLinks}>
        <Link to="/generate" style={linkStyle}>
          <LayoutDashboard size={16} /> GENERATE
        </Link>
        <Link to="/vault" style={linkStyle}>
          <Archive size={16} /> VAULT
        </Link>
        <Link to="/live" style={linkStyle}>
          <Activity size={16} /> LIVE_PULSE
        </Link>
      </div>

      {/* ── User Actions (Right) ── */}
      <div style={userSection}>
        {user ? (
          <>
            <div style={userInfo}>
              <span style={userLabel}>OPERATOR</span>
              <span style={userName}>{user.full_name?.toUpperCase()}</span>
            </div>
            <button onClick={handleLogout} style={logoutBtn}>
              <LogOut size={16} />
            </button>
          </>
        ) : (
          <Link to="/login" style={loginBtn}>INITIALIZE_SESSION</Link>
        )}
      </div>
    </nav>
  );
};

/* --- FULL SCREEN NAVBAR STYLES --- */
const navWrapper = {
  width: '100vw',             // Force full viewport width
  height: '70px',
  background: '#0a0b0e',      // Charcoal background
  borderBottom: '1px solid var(--surface-border)',
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  padding: '0 2rem',          // Padding only on sides
  boxSizing: 'border-box',
  position: 'sticky',
  top: 0,
  zIndex: 1000,
};

const brandLink = {
  display: 'flex',
  alignItems: 'center',
  gap: '12px',
  textDecoration: 'none'
};

const brandText = {
  fontSize: '1rem',
  fontWeight: 900,
  color: '#fff',
  letterSpacing: '0.15em',
  fontFamily: 'monospace'
};

const navLinks = {
  display: 'flex',
  gap: '2.5rem',
  alignItems: 'center'
};

const linkStyle = {
  textDecoration: 'none',
  color: 'var(--text-muted)',
  fontSize: '0.7rem',
  fontWeight: 800,
  letterSpacing: '0.1em',
  display: 'flex',
  alignItems: 'center',
  gap: '8px',
  transition: 'color 0.2s ease',
  fontFamily: 'monospace'
};

const userSection = {
  display: 'flex',
  alignItems: 'center',
  gap: '20px'
};

const userInfo = {
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'flex-end'
};

const userLabel = {
  fontSize: '0.5rem',
  color: 'var(--accent-primary)',
  fontWeight: 900,
  letterSpacing: '0.1em'
};

const userName = {
  fontSize: '0.75rem',
  color: '#fff',
  fontWeight: 700,
  fontFamily: 'monospace'
};

const logoutBtn = {
  background: 'rgba(239, 68, 68, 0.1)',
  border: '1px solid rgba(239, 68, 68, 0.2)',
  color: '#ef4444',
  padding: '8px',
  borderRadius: '8px',
  cursor: 'pointer',
  display: 'flex',
  alignItems: 'center',
  transition: 'all 0.2s ease'
};

const loginBtn = {
  background: 'var(--accent-primary)',
  color: '#000',
  padding: '8px 16px',
  borderRadius: '6px',
  textDecoration: 'none',
  fontSize: '0.7rem',
  fontWeight: 900
};

export default Navbar;
